void logos_setup(logos_graph *g) {
}

int main(int argc, char **argv) {
    logos_argc = argc; logos_argv = argv;
    logos_graph graph;
    logos_graph_init(&graph);
    logos_env   env   = {0};
    logos_env_init(&env);
    env.graph = &graph;
    logos_setup(&graph);

    {
        int    _found = 0;
        double _conf  = 0.0;
        env.capture_found = &_found;
        env.capture_conf  = &_conf;
        env.confidence    = 1.0;
        pred_compile_main(&env, logos_string("done"), k_bool_capture);
        logos_print_bool_result("compile-main(\"done\")", _found, _conf);
    }
    return 0;
}
